Here's an example of a Discord bot using Discord.js v14 with a slash command called `ban`. Make sure you have Node.js installed and create a new project with `npm init -y`. Also, install Discord.js by running `npm install discord.js`.

First, create a new file named `index.js`. Here's the code:

```javascript
const { Client, Intents, SlashCommandBuilder } = require('discord.js');
const fs = require('fs');

const client = new Client({ intents: [Intents.FLAGS.Guilds, Intents.FLAGS.GuildMessages, Intents.FLAGS.GuildMembers, Intents.FLAGS.MessageContent, Intents.FLAGS.DirectMessages, Intents.FLAGS.Presence] });

client.commands = new Map();
const commandFiles = fs.readdirSync('./commands').filter(file => file.endsWith('.js'));

for (const file of commandFiles) {
  const commands = require(`./commands/${file}`);
  client.commands.set(commands.name, commands);
}

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const command = client.commands.get(interaction.commandName);

  try {
    await command.execute(interaction);
  } catch (error) {
    console.error(error);
    await interaction.reply({ content: 'There was an error trying to execute that command!', ephemeral: true });
  }
});

client.login('YOUR_BOT_TOKEN');

const banCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Bans a user from the server')
  .addUserOption(option => option.setName('user').setDescription('The user to ban').setRequired(true))
  .addStringOption(option => option.setName('reason').setDescription('The reason for the ban').setRequired(false));

const banCommandFile = {
  name: 'ban',
  execute: async interaction => {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason');

    await interaction.guild.members.ban(user, { reason: reason });

    await interaction.reply(`Successfully banned ${user.tag} with reason: ${reason}`);
  },
};

client.commands.set(banCommand.toJSON().name, banCommandFile);
```

Replace `'YOUR_BOT_TOKEN'` with your bot's token. Create a new directory named `commands` and create a new file inside that directory named `ban.js` with the following content:

```javascript
module.exports = {
  name: 'ban',
};
```

Now you have a Discord bot with a slash command called `ban` using Discord.js v14. The bot can ban users from a server with the provided command.

