Here's a simple example showing how to load images using the SDL library:

```c
#include <stdio.h>
#include <SDL.h>
#include <SDL_image.h>

int main(int argc, char* args[])
{
    SDL_Window* window = NULL;
    SDL_Surface* screenSurface = NULL;
    SDL_Surface* img = NULL;

    if (SDL_Init(SDL_INIT_VIDEO) < 0)
    {
        printf("Unable to initialize SDL: %s\n", SDL_GetError());
        return -1;
    }

    window = SDL_CreateWindow("sdl window", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 640, 480, SDL_WINDOW_SHOWN);
    if (!window)
    {
        printf("Unable to create window: %s\n", SDL_GetError());
        SDL_Quit();
        return -1;
    }

    screenSurface = SDL_GetWindowSurface(window);

    img = IMG_Load("snake.png");
    if (!img)
    {
        printf("Unable to load image: %s\n", IMG_GetError());
        SDL_FreeSurface(img);
        SDL_DestroyWindow(window);
        SDL_Quit();
        return -1;
    }

    // Rendering the image to the screen
    SDL_BlitSurface(img, NULL, screenSurface, 0, 0);

    SDL_UpdateWindowSurface(window);

    SDL_FreeSurface(img);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```

